INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-416.5, 54, 10113003, 0.0, 3, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, 1, "2023/02/26 14:59:59", "カリン", "2023/02/14 12:00:00", 10113, 190801, 2.801);
