INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-416.5, 53, 20047002, 0.0, 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 2, 1, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 3.099);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-416.5, 54, 20047003, 0.0, 3, "受け取ることができる\n報酬があるようです\n確認してみてください", 2, 1, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 2.801);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-416.5, 54, 20047004, 0.0, 4, "報酬がもらえますよ！\nチェックしてみてください", 2, 2, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 0.0);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-416.5, 57, 20047005, 0.0, 5, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 1, 1, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 0.0);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-363.0, 55, 20047006, 0.0, 1, "ギルド管理協会です！\n討伐証をお持ちでしたら、\n報酬交換できますよ", 2, 1, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 5.506);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-363.0, 55, 20047007, 0.0, 2, "お疲れ様です！\nここでは、討伐証と報酬を\n交換することができます！", 1, 2, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 1.216);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-363.0, 56, 20047008, 0.0, 3, "お疲れ様でした\n討伐証の交換、\nお忘れないように！", 1, 2, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 1.539);
INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-363.0, 56, 20047009, 0.0, 4, "終わっちゃいましたねー\n討伐証は努力の証！\n報酬と交換しましょう！", 1, 2, "2030/01/01 14:59:59", "カリン", "2023/11/16 15:00:00", 20047, 190801, 1.875);
