INSERT INTO `v1_f7899988d1c9040448129a7ec244301377a4a7dfb4a04dcd96c6d3f93e7cd469` VALUES (-416.5, 57, 20075005, 0.0, 5, "イベントお疲れ様です！\n皆さんのご活躍ぶりには\nいつも感謝しています", 1, 1, "2030/01/01 14:59:59", "カリン", "2026/03/17 15:00:00", 20075, 190801, 0.0);
